}

if(action==='defi'||action==='capital'){
  const seed=parseFloat(b.seed||b.capital||50);
  const ltv=parseFloat(b.ltv||0.65);
  const depth=parseInt(b.depth||5);
  const apy=parseFloat(b.apy||0.28);
